export function getSortedBlogPosts(): BlogPost[] {
  const chapter0 = blogPosts.find(post => post.slug === "seo-prompts-2026")
  const otherPosts = blogPosts.filter(post => post.slug !== "seo-prompts-2026")
  
  // Convert month/year string to date for sorting
  function parseDate(dateStr: string): Date {
    const parts = dateStr.trim().split(/\s+/)
    if (parts.length < 2) return new Date(2026, 0, 1)
    
    const [monthStr, yearStr] = parts
    const year = parseInt(yearStr, 10) || 2026
    
    const monthMap: Record<string, number> = {
      Jan: 0, Feb: 1, Mar: 2, Apr: 3, May: 4, Jun: 5,
      Jul: 6, Aug: 7, Sep: 8, Oct: 9, Nov: 10, Dec: 11,
      January: 0, February: 1, March: 2, April: 3, May: 4, June: 5,
      July: 6, August: 7, September: 8, October: 9, November: 10, December: 11
    }
    
    const month = monthMap[monthStr] !== undefined ? monthMap[monthStr] : 0
    return new Date(year, month, 1)
  }

  otherPosts.sort((a, b) => {
    const dateA = parseDate(a.date).getTime()
    const dateB = parseDate(b.date).getTime()
    
    // Different dates: sort by date (newest first)
    if (dateB !== dateA) {
      return dateB - dateA
    }
    
    // Same date: check if both are in series
    const indexA = seriesOrder.indexOf(a.slug)
    const indexB = seriesOrder.indexOf(b.slug)
    
    // Both in series: sort by series order
    if (indexA !== -1 && indexB !== -1) {
      return indexA - indexB
    }
    
    // Only A is in series: B comes first (non-series posts first)
    if (indexA !== -1) return 1
    
    // Only B is in series: A comes first (non-series posts first)
    if (indexB !== -1) return -1
    
    // Neither in series: sort alphabetically by title
    return a.title.localeCompare(b.title)
  })
  
  return chapter0 ? [chapter0, ...otherPosts] : otherPosts
}

export function isSEOSeriesPost(slug: string): boolean {
  return seriesOrder.includes(slug)
}

export function getSEOSeriesNavigation(currentSlug: string): { prev: BlogPost | null, next: BlogPost | null } {
  const currentIndex = seriesOrder.indexOf(currentSlug)
  if (currentIndex === -1) {
    return { prev: null, next: null }
  }
  
  const prevSlug = currentIndex > 0 ? seriesOrder[currentIndex - 1] : null
  const nextSlug = currentIndex < seriesOrder.length - 1 ? seriesOrder[currentIndex + 1] : null
  
  return {
    prev: prevSlug ? getBlogPost(prevSlug) || null : null,
    next: nextSlug ? getBlogPost(nextSlug) || null : null
  }
}
